    /**
     * Validates that all query parameter keys and values contain only safe characters.
     */
    private boolean validateQueryParamsFormat(Map<String, String> params) {
        if (params == null) return true;

        // Limit number of query parameters
        if (params.size() > 10) {
            Log.w(TAG, "Too many query parameters");
            return false;
        }

        for (Map.Entry<String, String> entry : params.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            if (key == null || !ALPHANUMERIC_PATTERN.matcher(key).matches()) {
                Log.w(TAG, "Invalid query parameter key");
                return false;
            }

            if (value != null && !ALPHANUMERIC_PATTERN.matcher(value).matches()) {
                Log.w(TAG, "Invalid query parameter value for key: " + sanitizeForLogging(key));
                return false;
            }
        }

        return true;
    }

