    static class DeepLinkRoute {
        final String host;
        final List<String> pathSegments;
        final Map<String, String> queryParams;

        DeepLinkRoute(String host, List<String> pathSegments, Map<String, String> queryParams) {
            this.host = host;
            this.pathSegments = pathSegments;
            this.queryParams = queryParams != null ? queryParams : new HashMap<>();
        }

        @Override
        public String toString() {
            return "DeepLinkRoute{host='" + host + "', pathSegments=" + pathSegments
                    + ", queryParams=" + queryParams.keySet() + "}";
        }
    }

